-- Verificar quantos duplicados existem antes
SELECT COUNT(*) as total_antes FROM spread_analysis;

-- Deletar duplicados: manter apenas o registro de maior id por codigoCetip
DELETE sa FROM spread_analysis sa
INNER JOIN (
  SELECT codigoCetip, MAX(id) AS maxId
  FROM spread_analysis
  GROUP BY codigoCetip
) latest ON sa.codigoCetip = latest.codigoCetip
WHERE sa.id < latest.maxId;

-- Verificar resultado
SELECT COUNT(*) as total_depois FROM spread_analysis;

